196	// commitCount returns the total number of commits reachable from ref.
197	func (r *landTestRepo) commitCount(ref string) int {
198		r.t.Helper()
199		out := r.runGit("rev-list", "--count", ref)
200		n := 0
201		_, _ = fmt.Sscanf(out, "%d", &n)
202		return n
