562	func waitForEmptyGitIndex(dir string, timeout time.Duration) error {
563		deadline := time.Now().Add(timeout)
564		for {
565			if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
566				return nil
567			}
568			if time.Now().After(deadline) {
569				stagedOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-status").CombinedOutput()
570				staged := strings.TrimSpace(string(stagedOut))
571				if staged == "" {
572					staged = "unknown staged changes"
573				}
574				return fmt.Errorf("landing worktree has staged changes after waiting %s:\n%s", timeout, staged)
575			}
576			time.Sleep(100 * time.Millisecond)
577		}
578	}
