1665	// ApplyLandResultToExecuteBeadResult maps a LandResult onto an
1666	// ExecuteBeadResult so the execute-bead loop sees the correct final status.
1667	// It is the coordinator-pattern replacement for ApplyLandingToResult.
1668	func ApplyLandResultToExecuteBeadResult(res *ExecuteBeadResult, land *LandResult) {
1669		if land == nil || res == nil {
1670			return
1671		}
1672		switch land.Status {
1673		case "landed":
1674			// Fast-forward or merge commit — either way the target branch now
1675			// contains the worker's result. ResultRev's own parent is still
1676			// BaseRev so replay fidelity is preserved.
1677			res.Outcome = "merged"
1678			res.Reason = ""
1679			res.PreserveRef = ""
1680			if land.Merged {
1681				res.Reason = "merged onto current tip"
1682			}
1683			if land.PushConflict {
1684				res.Reason = PushConflictReasonPrefix + " " + land.PushError
1685			} else if land.PushFailed {
1686				res.Reason = PushFailedReasonPrefix + " " + land.PushError
1687			}
1688			if land.CheckoutSyncDeferred {
1689				detail := "checkout_sync_deferred"
1690				if len(land.CheckoutSyncDeferredPaths) > 0 {
1691					detail += ": " + strings.Join(land.CheckoutSyncDeferredPaths, ", ")
1692				}
1693				if res.Reason == "" {
1694					res.Reason = detail
1695				} else {
1696					res.Reason += "; " + detail
1697				}
1698			}
1699			// NewTip reflects the ref actually on the target branch (either
1700			// ResultRev on the ff path or the merge commit SHA on the merge path).
1701			if land.NewTip != "" {
1702				// Preserve the implementation rev before rewriting the compat alias.
1703				if res.ImplementationRev == "" {
1704					res.ImplementationRev = res.ResultRev
1705				}
1706				res.LandedRev = land.NewTip
1707				res.ResultRev = land.NewTip // backwards-compat alias mirrors LandedRev
1708			}
1709		case "preserved":
1710			res.Outcome = "preserved"
1711			res.Reason = land.Reason
1712			res.PreserveRef = land.PreserveRef
1713		case "no-changes":
1714			// Only overwrite when the worker itself did not already report
1715			// a richer no-changes rationale.
1716			if res.Outcome == "" || res.Outcome == ExecuteBeadOutcomeTaskSucceeded {
1717				res.Outcome = "no-changes"
1718			}
1719			if res.Reason == "" {
1720				res.Reason = land.Reason
1721			}
1722		}
1723		// Re-classify loop-visible status from the landing outcome.
1724		reasonForStatus := res.Reason
1725		if land.Status == "preserved" {
1726			// Route preserve reasons through the land-conflict classifier so the
1727			// loop sees land_conflict (not generic success).
1728			if strings.HasPrefix(res.Reason, PreMergeChecksReason) {
1729				reasonForStatus = res.Reason
1730			} else {
1731				reasonForStatus = "merge conflict"
1732			}
1733		}
1734		res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, reasonForStatus)
1735		res.OrchestratorStatus = res.Status
1736		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
1737	}
