// TestStageDirForcesGitIgnored verifies that StageDir adds files even when the
// target path is covered by .gitignore. Without --force, git add silently skips
// gitignored paths (exit 0, no output, no error), causing evidence commits to
// silently produce nothing.
func TestStageDirForcesGitIgnored(t *testing.T) {
	r := newLandTestRepo(t)

	// Ignore .ddx/executions/ the same way the DDx default .gitignore does.
	r.writeFile(".gitignore", ".ddx/executions/\n")

	attemptID := "20260510T000000-gitignore-stagetest"
	evidenceDir := filepath.Join(".ddx", "executions", attemptID)
	r.writeFile(filepath.Join(evidenceDir, "manifest.json"), `{"attempt_id":"`+attemptID+`"}`)

	ops := RealLandingGitOps{}
	relPath := filepath.ToSlash(evidenceDir)
	if err := ops.StageDir(r.dir, relPath); err != nil {
		t.Fatalf("StageDir failed: %v", err)
	}

	cached := r.runGit("diff", "--cached", "--name-only")
	wantSubstr := "manifest.json"
	if !strings.Contains(cached, wantSubstr) {
		t.Fatalf("gitignored file not staged after StageDir --force: diff --cached = %q", cached)
	}
}

// TestEvidenceCommitSucceedsWhenGitignored verifies that Land() lands cleanly
// even when the project's .gitignore covers .ddx/executions/. This was the
// failure mode in fizeau and any repo using the standard DDx gitignore template:
// StageDir without --force silently staged nothing, CommitStaged returned sha="",
// and landEvidence preserved instead of landing.
func TestEvidenceCommitSucceedsWhenGitignored(t *testing.T) {
	r := newLandTestRepo(t)

	// Commit a .gitignore that covers .ddx/executions/ so the finalization
	// worktree checks it out and respects it during git add.
	r.writeFile(".gitignore", ".ddx/executions/\n")
	r.runGit("add", ".gitignore")
	r.runGit("commit", "-m", "chore: add gitignore")
	r.baseSHA = r.resolveRef("refs/heads/main")

	attemptID := "20260510T000000-gitignore-evidencetest"
	evidenceDir := filepath.Join(".ddx", "executions", attemptID)
	fullDir := filepath.Join(r.dir, evidenceDir)
	if err := os.MkdirAll(fullDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(fullDir, "manifest.json"), []byte(`{"attempt_id":"`+attemptID+`"}`), 0o644); err != nil {
		t.Fatal(err)
	}

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: feature")
	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-gitignored-evidence",
		AttemptID:    attemptID,
		TargetBranch: "main",
		EvidenceDir:  filepath.ToSlash(evidenceDir),
	}
	land, err := Land(r.dir, req, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("status = %q reason=%q, want landed", land.Status, land.Reason)
	}
	if land.EvidenceCommitSHA == "" {
		t.Fatal("expected evidence commit SHA to be set")
	}
}

